import{_ as e,c as a,o as i,ag as o}from"./chunks/framework.QPV3Ar9-.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/guide/qemu/qemu_precheck.md","filePath":"en/guide/qemu/qemu_precheck.md","lastUpdated":1772612081000}'),r={name:"en/guide/qemu/qemu_precheck.md"};function s(n,t,l,d,c,u){return i(),a("div",null,t[0]||(t[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The following is an introduction to the non-customized part. The customized part has its own corresponding introduction; please do not mix them up.</p><p>Please give the project a <code>Star</code> for free support --&gt; <a href="https://github.com/oneclickvirt/qemu" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/qemu</a></p><h2 id="project-features" tabindex="-1">Project Features <a class="header-anchor" href="#project-features" aria-label="Permalink to &quot;Project Features&quot;">​</a></h2><p>Virtualization based on QEMU/KVM, supporting batch or individual creation of KVM virtual machines without needing Proxmox VE or Incus management platforms</p><ul><li>Pure QEMU/KVM virtualization solution, lightweight with no additional management platform required</li><li>Each virtual machine comes with its own dedicated SSH port and port mapping</li><li>Supports IPv4/IPv6 automatic allocation and port forwarding</li><li>Supports batch creation with automatic logging to a log file</li><li>Supports X86_64 and ARM64 architectures</li><li>Supports domestic CDN mirror acceleration</li></ul><h2 id="supported-systems-host" tabindex="-1">Supported Systems (Host) <a class="header-anchor" href="#supported-systems-host" aria-label="Permalink to &quot;Supported Systems (Host)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>amd64</th><th>arm64</th></tr></thead><tbody><tr><td>Debian 11</td><td>✓</td><td>✓</td></tr><tr><td>Debian 12</td><td>✓</td><td>✓</td></tr><tr><td>Ubuntu 20.04</td><td>✓</td><td>✓</td></tr><tr><td>Ubuntu 22.04</td><td>✓</td><td>✓</td></tr></tbody></table><h2 id="configuration-requirements" tabindex="-1">Configuration Requirements <a class="header-anchor" href="#configuration-requirements" aria-label="Permalink to &quot;Configuration Requirements&quot;">​</a></h2><ul><li>Host must support KVM hardware virtualization (<code>/dev/kvm</code> available)</li><li>Kernel version: ≥ 4.15</li><li>Architecture: x86_64 (amd64) or ARM64</li><li>Memory: at least 1GB available (excluding host OS overhead)</li><li>Storage: at least 10GB available disk space</li><li>OS: Debian 11+, Ubuntu 20.04+</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Before using this project, make sure the host supports KVM virtualization. You can check with the following command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">egrep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;(vmx|svm)&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/cpuinfo</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>A result greater than 0 indicates KVM virtualization is supported. You can also run <code>ls /dev/kvm</code> to confirm the device file exists.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If the host does not have an IPv6 subnet but you want to assign IPv6 addresses to virtual machines, the host itself must have a public IPv6 address. The installation script will automatically detect and configure this.</p></div><p>It is recommended to add some SWAP virtual memory before creating virtual machines to avoid sudden memory usage causing the host to crash.</p>',13)]))}const m=e(r,[["render",s]]);export{h as __pageData,m as default};
